/* ──────────────────────────────────────────────────────────────
   FlowDesigner.tsx
   Architecture and request-flow designer with cost controls.
   ────────────────────────────────────────────────────────────── */
import React, { useMemo } from 'react';
import { Node } from 'react-flow-renderer';
import { ServiceNodeData } from './ServiceNode';
import { CostConfig, FlowSummary, RequestFlow, CostTotals } from './flowModel';

export interface FlowDesignerProps {
  nodes: Node<ServiceNodeData>[];
  flows: RequestFlow[];
  flowSummaries: FlowSummary[];
  totals: CostTotals;
  costConfig: CostConfig;
  onFlowAdd: () => void;
  onFlowRemove: (id: string) => void;
  onFlowChange: (id: string, patch: Partial<RequestFlow>) => void;
  onCostConfigChange: (patch: Partial<CostConfig>) => void;
  onReplicasChange: (nodeId: string, replicas: number) => void;
}

function formatMoney(value: number): string {
  const safe = Number.isFinite(value) ? value : 0;
  return `$${safe.toFixed(2)}`;
}

export default function FlowDesigner({
  nodes,
  flows,
  flowSummaries,
  totals,
  costConfig,
  onFlowAdd,
  onFlowRemove,
  onFlowChange,
  onCostConfigChange,
  onReplicasChange,
}: FlowDesignerProps) {
  const nodeOptions = useMemo(
    () =>
      nodes.map((n) => {
        const d = n.data as ServiceNodeData;
        const label = d.instanceLabel ? `${d.label} (${d.instanceLabel})` : d.label;
        return { id: n.id, label };
      }),
    [nodes]
  );

  const summaryById = useMemo(() => {
    const map = new Map<string, FlowSummary>();
    for (const s of flowSummaries) map.set(s.flowId, s);
    return map;
  }, [flowSummaries]);

  return (
    <aside className="flow-designer">
      <div className="flow-header">
        <h3>Architecture + Flows</h3>
        <p className="flow-hint">AWS cost estimates. Update rates as needed.</p>
      </div>

      <section className="flow-section">
        <h4>Services</h4>
        {nodes.length === 0 && <p className="muted">Add services to the canvas.</p>}
        {nodes.map((n) => {
          const d = n.data as ServiceNodeData;
          const label = d.instanceLabel ? `${d.label} (${d.instanceLabel})` : d.label;
          return (
            <div className="flow-row" key={n.id}>
              <span className="flow-label">{label}</span>
              <input
                className="input-compact"
                type="number"
                min={1}
                value={d.replicas ?? 1}
                onChange={(e) => onReplicasChange(n.id, Number(e.target.value) || 1)}
                title="Replicas"
              />
            </div>
          );
        })}
      </section>

      <section className="flow-section">
        <h4>Cost Model</h4>
        <div className="cost-grid">
          <label>
            vCPU per hour
            <input
              type="number"
              step="0.001"
              value={costConfig.vcpuPerHr}
              onChange={(e) => onCostConfigChange({ vcpuPerHr: Number(e.target.value) })}
            />
          </label>
          <label>
            Memory GB per hour
            <input
              type="number"
              step="0.001"
              value={costConfig.memoryGbPerHr}
              onChange={(e) => onCostConfigChange({ memoryGbPerHr: Number(e.target.value) })}
            />
          </label>
          <label>
            Compute per 1M req
            <input
              type="number"
              step="0.01"
              value={costConfig.computePerMReq}
              onChange={(e) => onCostConfigChange({ computePerMReq: Number(e.target.value) })}
            />
          </label>
          <label>
            Database base per hour
            <input
              type="number"
              step="0.01"
              value={costConfig.databaseBasePerHr}
              onChange={(e) => onCostConfigChange({ databaseBasePerHr: Number(e.target.value) })}
            />
          </label>
          <label>
            Database per 1M req
            <input
              type="number"
              step="0.01"
              value={costConfig.databasePerMReq}
              onChange={(e) => onCostConfigChange({ databasePerMReq: Number(e.target.value) })}
            />
          </label>
          <label>
            Streaming base per hour
            <input
              type="number"
              step="0.01"
              value={costConfig.streamingBasePerHr}
              onChange={(e) => onCostConfigChange({ streamingBasePerHr: Number(e.target.value) })}
            />
          </label>
          <label>
            Streaming per 1M req
            <input
              type="number"
              step="0.01"
              value={costConfig.streamingPerMReq}
              onChange={(e) => onCostConfigChange({ streamingPerMReq: Number(e.target.value) })}
            />
          </label>
          <label>
            Analytics base per hour
            <input
              type="number"
              step="0.01"
              value={costConfig.analyticsBasePerHr}
              onChange={(e) => onCostConfigChange({ analyticsBasePerHr: Number(e.target.value) })}
            />
          </label>
          <label>
            Analytics per 1M req
            <input
              type="number"
              step="0.01"
              value={costConfig.analyticsPerMReq}
              onChange={(e) => onCostConfigChange({ analyticsPerMReq: Number(e.target.value) })}
            />
          </label>
        </div>
      </section>

      <section className="flow-section">
        <div className="flow-section-header">
          <h4>Request Flows</h4>
          <button className="btn-secondary" onClick={onFlowAdd}>
            Add Flow
          </button>
        </div>
        {flows.length === 0 && <p className="muted">Create a flow to analyze latency and cost.</p>}
        {flows.map((flow) => {
          const summary = summaryById.get(flow.id);
          return (
            <div className="flow-card" key={flow.id}>
              <div className="flow-card-header">
                <input
                  className="flow-name"
                  value={flow.name}
                  onChange={(e) => onFlowChange(flow.id, { name: e.target.value })}
                />
                <button className="flow-remove" onClick={() => onFlowRemove(flow.id)}>
                  Remove
                </button>
              </div>
              <div className="flow-grid">
                <label>
                  Source
                  <select
                    value={flow.sourceId}
                    onChange={(e) => onFlowChange(flow.id, { sourceId: e.target.value })}
                  >
                    <option value="">Select</option>
                    {nodeOptions.map((n) => (
                      <option key={n.id} value={n.id}>
                        {n.label}
                      </option>
                    ))}
                  </select>
                </label>
                <label>
                  Target
                  <select
                    value={flow.targetId}
                    onChange={(e) => onFlowChange(flow.id, { targetId: e.target.value })}
                  >
                    <option value="">Select</option>
                    {nodeOptions.map((n) => (
                      <option key={n.id} value={n.id}>
                        {n.label}
                      </option>
                    ))}
                  </select>
                </label>
                <label>
                  RPS
                  <input
                    type="number"
                    min={0}
                    value={flow.rps}
                    onChange={(e) => onFlowChange(flow.id, { rps: Number(e.target.value) })}
                  />
                </label>
                <label>
                  Payload KB
                  <input
                    type="number"
                    min={0}
                    value={flow.payloadKb}
                    onChange={(e) => onFlowChange(flow.id, { payloadKb: Number(e.target.value) })}
                  />
                </label>
              </div>
              <div className="flow-summary">
                {summary?.missingPath ? (
                  <span className="muted">No path found between source and target.</span>
                ) : (
                  <>
                    <span className="flow-path">{summary?.pathLabels.join(' -> ')}</span>
                    <span className="flow-metrics">
                      {summary?.latencyMs} ms | {formatMoney(summary?.monthlyCost ?? 0)} / mo
                    </span>
                  </>
                )}
              </div>
            </div>
          );
        })}
      </section>

      <section className="flow-section">
        <h4>Cost Summary</h4>
        <div className="flow-summary-grid">
          <div>
            <span>Base infra</span>
            <strong>{formatMoney(totals.baseMonthly)} / mo</strong>
          </div>
          <div>
            <span>Request driven</span>
            <strong>{formatMoney(totals.variableMonthly)} / mo</strong>
          </div>
          <div>
            <span>Total</span>
            <strong>{formatMoney(totals.totalMonthly)} / mo</strong>
          </div>
        </div>
      </section>
    </aside>
  );
}
